"use client";
import React from "react";
import { SWRConfig } from "swr";
export function Auth0Provider({ user, children, profileRoute }) {
    const route = profileRoute || process.env.NEXT_PUBLIC_PROFILE_ROUTE || "/auth/profile";
    return (React.createElement(SWRConfig, { value: {
            fallback: {
                [route]: user
            }
        } }, children));
}
